class Solution:
    def getMaxGridHappiness(self, m: int, n: int, introvertsCount: int, extrovertsCount: int) -> int:
        total_cells = m * n
        best = [-1]

        def score(grid):
            total = 0
            for r in range(m):
                for c in range(n):
                    person = grid[r][c]
                    if person == 0:
                        continue
                    total += 120 if person == 1 else 40
                    for dr, dc in ((-1, 0), (1, 0), (0, -1), (0, 1)):
                        nr, nc = r + dr, c + dc
                        if 0 <= nr < m and 0 <= nc < n and grid[nr][nc] != 0:
                            total += -30 if person == 1 else 20
            return total

        grid = [[0] * n for _ in range(m)]

        def backtrack(idx, intro, extro):
            if idx == total_cells:
                cand = score(grid)
                if cand > best[0]:
                    best[0] = cand
                return
            r, c = divmod(idx, n)
            grid[r][c] = 0
            backtrack(idx + 1, intro, extro)
            if intro > 0:
                grid[r][c] = 1
                backtrack(idx + 1, intro - 1, extro)
            if extro > 0:
                grid[r][c] = 2
                backtrack(idx + 1, intro, extro - 1)
            grid[r][c] = 0

        backtrack(0, introvertsCount, extrovertsCount)
        return best[0]

