from functools import lru_cache


class Solution:
    def getMaxGridHappiness(self, m: int, n: int, introvertsCount: int, extrovertsCount: int) -> int:
        total_cells = m * n
        pow_n = 3 ** n

        def contrib(person, other):
            if other == 0:
                return 0
            delta = -30 if person == 1 else 20
            delta += -30 if other == 1 else 20
            return delta

        @lru_cache(maxsize=None)
        def dp(idx, intro, extro, mask):
            if idx == total_cells:
                return 0
            row, col = divmod(idx, n)
            up = (mask // (pow_n // 3)) if row > 0 else 0
            left = (mask % 3) if col > 0 else 0
            best = dp(idx + 1, intro, extro, (mask * 3) % pow_n)
            if intro > 0:
                gain = 120
                if row > 0:
                    gain += contrib(1, up)
                if col > 0:
                    gain += contrib(1, left)
                cand = gain + dp(idx + 1, intro - 1, extro, (mask * 3 + 1) % pow_n)
                if cand > best:
                    best = cand
            if extro > 0:
                gain = 40
                if row > 0:
                    gain += contrib(2, up)
                if col > 0:
                    gain += contrib(2, left)
                cand = gain + dp(idx + 1, intro, extro - 1, (mask * 3 + 2) % pow_n)
                if cand > best:
                    best = cand
            return best

        return dp(0, introvertsCount, extrovertsCount, 0)

