var getMaxGridHappiness = function(m, n, introvertsCount, extrovertsCount) {
    const totalCells = m * n;
    const powN = Math.pow(3, n);

    function contrib(person, other) {
        if (other === 0) return 0;
        let delta = person === 1 ? -30 : 20;
        delta += other === 1 ? -30 : 20;
        return delta;
    }

    const memo = new Map();

    function dp(idx, intro, extro, mask) {
        if (idx === totalCells) return 0;
        const key = idx + ',' + intro + ',' + extro + ',' + mask;
        const cached = memo.get(key);
        if (cached !== undefined) return cached;
        const row = Math.floor(idx / n);
        const col = idx % n;
        const up = row > 0 ? Math.floor(mask / (powN / 3)) : 0;
        const left = col > 0 ? mask % 3 : 0;
        let best = dp(idx + 1, intro, extro, (mask * 3) % powN);
        if (intro > 0) {
            let gain = 120;
            if (row > 0) gain += contrib(1, up);
            if (col > 0) gain += contrib(1, left);
            const cand = gain + dp(idx + 1, intro - 1, extro, (mask * 3 + 1) % powN);
            if (cand > best) best = cand;
        }
        if (extro > 0) {
            let gain = 40;
            if (row > 0) gain += contrib(2, up);
            if (col > 0) gain += contrib(2, left);
            const cand = gain + dp(idx + 1, intro, extro - 1, (mask * 3 + 2) % powN);
            if (cand > best) best = cand;
        }
        memo.set(key, best);
        return best;
    }

    return dp(0, introvertsCount, extrovertsCount, 0);
};
